fn precall_c(
    state: &mut LuaState,
    func_idx: StackIdx,
    nresults: i32,
    f: crate::state::LuaCFunction,
) -> Result<i32, LuaError> {
    // C: checkstackGCp(L, LUA_MINSTACK, func)
    state.check_stack(LUA_MINSTACK as i32)?;
    state.gc_check_step();

    let top_idx = state.top_idx();
    // C: L->ci = ci = prepCallInfo(L, func, nresults, CIST_C, L->top.p + LUA_MINSTACK)
