    // C: lua_assert(ci->top.p <= L->stack_last.p)
    debug_assert!(true /* TODO(phase-b): state.get_ci(ci_idx).top <= state.stack_last */);

    // C: if (l_unlikely(L->hookmask & LUA_MASKCALL))
